example.code:
/* Fix: scroll focused elements clear of sticky header */
:focus {
  scroll-margin-top: 80px; /* match sticky header height */
}

/* WCAG 2.2 AA minimum */
.btn { min-width: 24px; min-height: 24px; }

/* Recommended for primary mobile actions (good practice, not 2.2 AA) */
@media (pointer: coarse) {
  .btn-primary { min-width: 44px; min-height: 44px; }
}
